                    $get('ctl00_ContentPlaceHolder1_hdnGenericId').value = item != null ? item.get_value() : sender.value();
                    $get('ctl00_ContentPlaceHolder1_hdnGenericName').value = item != null ? item.get_text() : sender.text();

                    $get('ctl00_ContentPlaceHolder1_hdnCIMSItemId').value = item != null ? item.get_attributes().getAttribute("CIMSItemId") : "";
